import{_ as t,c as l,o as i,a5 as r,j as a}from"./chunks/framework.Dtwt352Q.js";const b=JSON.parse('{"title":"v1.2.3：数据库稳定性增强","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.2.3.md","filePath":"changelog/v1.2.3.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.2.3.md"};function n(o,e,d,s,c,p){return i(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="v1-2-3-数据库稳定性增强" tabindex="-1">v1.2.3：数据库稳定性增强 <a class="header-anchor" href="#v1-2-3-数据库稳定性增强" aria-label="Permalink to “v1.2.3：数据库稳定性增强”">​</a></h1><p><strong>发布日期</strong>：2026年2月15日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新提升了<strong>数据库的稳定性和可靠性</strong>，修复了一些模型变体识别的问题。</p><hr><h2 id="新功能-数据库检查点" tabindex="-1">新功能：数据库检查点 <a class="header-anchor" href="#新功能-数据库检查点" aria-label="Permalink to “新功能：数据库检查点”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>为 SQLite 数据库添加了 WAL（Write-Ahead Logging）检查点机制。</p><h3 id="wal-检查点是什么" tabindex="-1">WAL 检查点是什么？ <a class="header-anchor" href="#wal-检查点是什么" aria-label="Permalink to “WAL 检查点是什么？”">​</a></h3><p>简单说，就是<strong>定期把临时数据写入主文件</strong>，防止数据丢失。</p><p>想象你在写文章：</p><ul><li><strong>没有检查点</strong>：所有内容都缓存着，电脑突然关机 → 内容丢失</li><li><strong>有检查点</strong>：每写一段就自动保存 → 不会丢太多内容</li></ul><h3 id="对用户有什么好处" tabindex="-1">对用户有什么好处？ <a class="header-anchor" href="#对用户有什么好处" aria-label="Permalink to “对用户有什么好处？”">​</a></h3><ul><li>更可靠的数据保存</li><li>数据库文件大小更合理</li><li>意外关闭时数据更安全</li></ul><hr><h2 id="问题修复-模型变体识别" tabindex="-1">问题修复：模型变体识别 <a class="header-anchor" href="#问题修复-模型变体识别" aria-label="Permalink to “问题修复：模型变体识别”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>使用 OpenRouter 等提供商时，某些 Anthropic 模型的变体可能无法正确识别。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>修复了这个问题，确保 OpenRouter 上的 Anthropic 模型也支持变体功能。</p><p>另外还修复了 Vercel Bedrock 模型的变体传递问题。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>使用 OpenRouter</td><td>✅ 升级</td></tr><tr><td>使用 Vercel Bedrock</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',26),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),r('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>确保 OpenRouter 上的 Anthropic 模型也支持变体</li><li>在数据库打开时添加 WAL 检查点</li><li>确保 Vercel 变体在 Bedrock 键下传递 Amazon 模型</li></ul></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const g=t(h,[["render",n]]);export{b as __pageData,g as default};
